'use client';

import { useState } from 'react';
import { Document, Page, pdfjs } from 'react-pdf';
import {
    ChevronLeft,
    ChevronRight,
    ZoomIn,
    ZoomOut,
    Download,
    RotateCw,
    Loader2,
} from 'lucide-react';

import 'react-pdf/dist/Page/AnnotationLayer.css';
import 'react-pdf/dist/Page/TextLayer.css';

// Set up the worker from CDN
pdfjs.GlobalWorkerOptions.workerSrc = `//unpkg.com/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.mjs`;

/**
 * PdfViewer - Main reusable PDF viewer component
 * 
 * Usage:
 * <PdfViewer 
 *   fileUrl="/path/to/file.pdf"
 *   fileName="document"
 *   onDownload={(url, name) => handleDownload(url, name)}
 * />
 */
export default function PdfViewer({ fileUrl, fileName = 'document', onDownload }) {
    const [numPages, setNumPages] = useState(null);
    const [currentPage, setCurrentPage] = useState(1);
    const [zoom, setZoom] = useState(100);
    const [rotation, setRotation] = useState(0);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState(null);

    // Handle PDF load success
    const onDocumentLoadSuccess = ({ numPages }) => {
        setNumPages(numPages);
        setIsLoading(false);
        setError(null);
    };

    // Handle PDF load error
    const onDocumentLoadError = (error) => {
        setError('Failed to load PDF');
        setIsLoading(false);
        console.error('PDF Load Error:', error);
    };

    // Navigation handlers
    const goToNextPage = () => {
        if (currentPage < numPages) {
            setCurrentPage(currentPage + 1);
        }
    };

    const goToPreviousPage = () => {
        if (currentPage > 1) {
            setCurrentPage(currentPage - 1);
        }
    };

    const goToPage = (pageNumber) => {
        const page = Math.max(1, Math.min(pageNumber, numPages || 1));
        setCurrentPage(page);
    };

    // Zoom handlers
    const handleZoomIn = () => {
        setZoom(Math.min(zoom + 25, 300));
    };

    const handleZoomOut = () => {
        setZoom(Math.max(zoom - 25, 50));
    };

    // Rotation handler
    const handleRotate = () => {
        setRotation((prev) => (prev + 90) % 360);
    };

    // Download handler
    const handleDownload = () => {
        if (onDownload) {
            onDownload(fileUrl, fileName);
        } else {
            const link = document.createElement('a');
            link.href = fileUrl;
            link.download = `${fileName}.pdf`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        }
    };

    // Page input handler
    const handlePageInput = (e) => {
        const value = parseInt(e.target.value);
        if (!isNaN(value)) {
            goToPage(value);
        }
    };

    return (
        <div className="flex flex-col h-full w-full bg-gradient-to-br from-[#0a0f1e] to-[#0f0f1e]">
            {/* Toolbar */}
            <div className="flex items-center justify-between gap-2 sm:gap-4 p-3 sm:p-4 bg-black/40 border-b border-white/10 backdrop-blur-md sticky top-0 z-40 flex-wrap">
                {/* Left Section - Page Navigation */}
                <div className="flex items-center gap-2">
                    {numPages && (
                        <div className="flex items-center gap-2 px-3 py-2 bg-white/5 rounded-lg border border-white/10">
                            <input
                                type="number"
                                min="1"
                                max={numPages}
                                value={currentPage}
                                onChange={handlePageInput}
                                className="w-10 sm:w-12 bg-transparent text-white text-center text-sm focus:outline-none font-semibold"
                            />
                            <span className="text-xs text-gray-500">/</span>
                            <span className="text-xs text-gray-400 w-8">{numPages}</span>
                        </div>
                    )}
                </div>

                {/* Center Section - Zoom Controls */}
                <div className="flex items-center gap-1 px-2 py-1 bg-white/5 rounded-lg border border-white/10">
                    <button
                        onClick={handleZoomOut}
                        className="p-2 hover:bg-white/10 rounded-md transition-colors text-gray-400 hover:text-white disabled:opacity-50"
                        title="Zoom Out"
                        disabled={zoom <= 50}
                    >
                        <ZoomOut size={16} />
                    </button>
                    <span className="text-xs font-semibold text-gray-400 w-10 text-center">{zoom}%</span>
                    <button
                        onClick={handleZoomIn}
                        className="p-2 hover:bg-white/10 rounded-md transition-colors text-gray-400 hover:text-white disabled:opacity-50"
                        title="Zoom In"
                        disabled={zoom >= 300}
                    >
                        <ZoomIn size={16} />
                    </button>
                </div>

                {/* Right Section - Actions */}
                <div className="flex items-center gap-2">
                    <button
                        onClick={handleRotate}
                        className="p-2 hover:bg-white/10 rounded-md transition-colors text-gray-400 hover:text-white"
                        title="Rotate 90°"
                    >
                        <RotateCw size={16} />
                    </button>

                    <button
                        onClick={handleDownload}
                        className="p-2 hover:bg-indigo-600/20 rounded-md transition-colors text-indigo-400 hover:text-indigo-300"
                        title="Download PDF"
                    >
                        <Download size={16} />
                    </button>
                </div>
            </div>

            {/* Content Area */}
            <div className="flex-1 overflow-auto bg-black/20 flex items-center justify-center">
                {isLoading && (
                    <div className="flex flex-col items-center justify-center">
                        <Loader2 size={40} className="text-indigo-400 animate-spin mb-3" />
                        <p className="text-sm text-gray-400">Loading PDF...</p>
                    </div>
                )}

                {error && (
                    <div className="text-center p-6 bg-red-950/30 border border-red-500/30 rounded-lg max-w-md">
                        <p className="text-red-400 font-semibold mb-2">Error Loading PDF</p>
                        <p className="text-sm text-red-300">{error}</p>
                    </div>
                )}

                {!isLoading && !error && (
                    <div className="flex flex-col items-center py-6 sm:py-8 px-4">
                        <Document
                            file={fileUrl}
                            onLoadSuccess={onDocumentLoadSuccess}
                            onLoadError={onDocumentLoadError}
                            loading={null}
                        >
                            {numPages && (
                                <div className="w-full max-w-4xl">
                                    <Page
                                        pageNumber={currentPage}
                                        scale={zoom / 100}
                                        rotate={rotation}
                                        renderTextLayer={true}
                                        renderAnnotationLayer={true}
                                        className="shadow-2xl mx-auto"
                                        width={Math.min(window.innerWidth - 40, 900)}
                                    />
                                </div>
                            )}
                        </Document>
                    </div>
                )}
            </div>

            {/* Bottom Navigation Bar */}
            {numPages && !isLoading && (
                <div className="flex items-center justify-between gap-4 p-3 sm:p-4 bg-black/40 border-t border-white/10 backdrop-blur-md sticky bottom-0 z-40">
                    <button
                        onClick={goToPreviousPage}
                        disabled={currentPage === 1}
                        className="p-2 hover:bg-white/10 rounded-lg transition-colors text-gray-400 hover:text-white disabled:opacity-50 disabled:cursor-not-allowed"
                        title="Previous Page"
                    >
                        <ChevronLeft size={18} />
                    </button>

                    <div className="flex items-center gap-2 text-sm text-gray-400">
                        <span>
                            Page <strong className="text-white">{currentPage}</strong> of{' '}
                            <strong className="text-white">{numPages}</strong>
                        </span>
                    </div>

                    <button
                        onClick={goToNextPage}
                        disabled={currentPage === numPages}
                        className="p-2 hover:bg-white/10 rounded-lg transition-colors text-gray-400 hover:text-white disabled:opacity-50 disabled:cursor-not-allowed"
                        title="Next Page"
                    >
                        <ChevronRight size={18} />
                    </button>
                </div>
            )}
        </div>
    );
}